export function measuredBlockHeight(blockId: string, fallback: number): number {
    const el = document.querySelector<HTMLElement>(`.drag-container[data-blockid="${blockId}"]`)
    return el ? el.getBoundingClientRect().height : fallback
}

layout__orderBy.body:
export function orderByPosition(
    blockIds: string[],
    fileId: string,
    layouts: LayoutDataSet,
    fallback: number,
): string[] {
    return [...blockIds].sort((idA, idB) => {
        const a = layouts[layoutKey(fileId, idA)]
        const b = layouts[layoutKey(fileId, idB)]
        const ay = a?.y ?? fallback, ax = a?.x ?? fallback
        const by = b?.y ?? fallback, bx = b?.x ?? fallback
        return (ay - by) || (ax - bx)
    })
}

selection__clip.body:
export class ClipboardManager {
    receiveEvent(
        eventData: unknown,
        reactEvent: React.SyntheticEvent | null,
        trigger: string,
        shape: DocShape,
        range: SelectionPoint[] = [],
    ): DocShape {
        const command = detectCommand(trigger, eventData)
        if (command === null) return freshShape(shape)   // not a clipboard keystroke

        // CM owns preventDefault for c/x/v so the browser's native clipboard does
        // not also fire. Synchronous — no awaits before this point.
        preventNativeClipboard(eventData)

        switch (command) {
            case "copy":
                copy(range, shape)            // fills the buffer; no document change
                return freshShape(shape)
            case "cut":
                return cut(range, shape)      // fills the buffer and removes the source
            case "paste":
                return paste(eventData, reactEvent, trigger, shape)
        }
    }
}

