cmdShiftArrowUp.body:
export function cmdShiftArrowUp(state: SelectionState, key: KeyEventData, blockOrder: string[]): SelectionState {
    const { anchor } = extendEnds(state, key);
    const firstBlock = blockOrder[0];
    if (!firstBlock) return state;
    return rangeBetween(anchor, pointAt(firstBlock, 0));   // to the start of the document
}

cmdShiftArrowDown.body:
export function cmdShiftArrowDown(state: SelectionState, key: KeyEventData, blockOrder: string[]): SelectionState {
    const { anchor } = extendEnds(state, key);
    const lastBlock = blockOrder[blockOrder.length - 1];
    if (!lastBlock) return state;
    return rangeBetween(anchor, pointAt(lastBlock, blockTextLength(lastBlock)));   // to the end of the document
}

selectAll.body:
export function selectAll(state: SelectionState, _key: KeyEventData, blockOrder: string[]): SelectionState {
    const firstBlock = blockOrder[0];
    const lastBlock  = blockOrder[blockOrder.length - 1];
    if (!firstBlock || !lastBlock) return state;

    const anchor = pointAt(firstBlock, 0);
    const focus  = pointAt(lastBlock, blockTextLength(lastBlock));
    return { anchor, focus, mode: "multi-block" };
}

SelectionPoint.body:
export interface SelectionPoint {
    blockId: string;
    offset: number;     // start of the selected span in this block (-1 = whole block)
    offsetEnd: number;  // end of the selected span in this block (-1 = whole block / caret has no span)
}

SelectionState.body:
export interface SelectionState {
    anchor: SelectionPoint | null;
    focus:  SelectionPoint | null;
    mode:   SelectionMode;
    // direction: "forward" | "backward // needs to be wired in. //would reduce chance of error and confusion wondering if ordering has already happened -> currently risky as SM builds range and deals with it using same names so confusing.
}

emptySelection.body:
export function emptySelection(): SelectionState {
    return { anchor: null, focus: null, mode: "caret" };
}

collapse.body:
export function collapse(state: SelectionState): SelectionState {
    return { ...state, focus: state.anchor, mode: "caret" };
}

selection__shape.body:
export function buildShape(
    shape: DocShape,
    state: SelectionState,
    snapshot: SelectionSnapshot,
    deleteSelection = false,
): DocShape {
    if (!deleteSelection) return passThrough(shape, snapshot);
    if (!isTextSelection(state)) return passThrough(shape, snapshot);

    const order = shape.file?.content ?? [];
    const span  = orderedSelectionRange(state, order);
    if (span.length === 0) return passThrough(shape, snapshot);

    return deleteSpan(shape, span, snapshot);
}

dom.body:
export function pointToPosition(clientX: number, clientY: number): SelectionPoint {
    const caret = caretPositionAt(clientX, clientY);
    if (!caret) return emptyPoint();

    const blockEl = blockElementContaining(caret.node);
    if (!blockEl) return emptyPoint();

    const offset = textOffsetWithin(blockEl, caret.node, caret.offset);
    return { blockId: blockIdOf(blockEl), offset, offsetEnd: offset };
}

handleKeyDown.body:
export function handleKeyDown(
    state: SelectionState,
    key: KeyEventData,
    blockOrder: string[],
): SelectionState {

    const cmd   = key.metaKey || key.ctrlKey;
    const event = key.nativeEvent;
    const pd    = () => { event?.preventDefault?.(); };

    switch (key.key) {

        case "Tab":
            pd();                       // suppress focus tab-out
            return state;

        case "Escape":
            pd();
            return { ...state, anchor: null, focus: null, mode: "caret" };

        case "Backspace":
        case "Delete":
            // The text removal itself happens in shapeBuilder (it owns document
            // edits). Here we only collapse the selection to a caret at the
            // start of the deleted span, so the caret lands correctly afterwards.
            // A collapsed selection (no span) is left to the browser's own
            // editing — SM does not preventDefault single-character deletes.
            if (!hasTextSpan(state)) return state;
            pd();
            return collapseToSpanStart(state, blockOrder);

        case "a":
            if (!cmd) return state;
            pd();
            return extend.selectAll(state, key, blockOrder);

        case "ArrowLeft":
            if (key.shiftKey && cmd) { pd(); return extend.cmdShiftArrowLeft(state, key, blockOrder); }
            if (key.shiftKey)        { pd(); return extend.shiftArrowLeft(state, key, blockOrder); }
            return caret.arrowLeft(state, key, blockOrder);   // native caret move; no preventDefault

        case "ArrowRight":
            if (key.shiftKey && cmd) { pd(); return extend.cmdShiftArrowRight(state, key, blockOrder); }
            if (key.shiftKey)        { pd(); return extend.shiftArrowRight(state, key, blockOrder); }
            return caret.arrowRight(state, key, blockOrder);

        case "ArrowUp":
            if (key.shiftKey && cmd) { pd(); return extend.cmdShiftArrowUp(state, key, blockOrder); }
            if (key.shiftKey)        { pd(); return extend.shiftArrowUp(state, key, blockOrder); }
            return caret.arrowUp(state, key, blockOrder);

        case "ArrowDown":
            if (key.shiftKey && cmd) { pd(); return extend.cmdShiftArrowDown(state, key, blockOrder); }
            if (key.shiftKey)        { pd(); return extend.shiftArrowDown(state, key, blockOrder); }
            return caret.arrowDown(state, key, blockOrder);

        default:
            return state;
    }
}

isDeleteKey.body:
export function isDeleteKey(key: KeyEventData): boolean {
    return key.key === "Backspace" || key.key === "Delete";
}

handleBlur.body:
export function handleBlur(
    state: SelectionState,
    _lifecycleData: LifecycleEventData,
): SelectionState {
    return state;
}

handleMouseDown.body:
export function handleMouseDown(
    _state: SelectionState,
    mouseData: MouseEventData,
): SelectionState {
    const point = pointToPosition(mouseData.clientX, mouseData.clientY);
    return { anchor: point, focus: point, mode: "caret" };
}

handleMouseDrag.body:
export function handleMouseDrag(
    state: SelectionState,
    mouseData: MouseEventData,
): SelectionState {
    if (mouseData.buttons === 0 || !state.anchor) return state;
    const point = pointToPosition(mouseData.clientX, mouseData.clientY);
    return { ...state, focus: point, mode: "range" };
}

handleMouseUp.body:
export function handleMouseUp(
    state: SelectionState,
    mouseData: MouseEventData,
): SelectionState {
    if (!state.anchor) return state;
    const point = pointToPosition(mouseData.clientX, mouseData.clientY);
    const mode  = isSamePoint(state.anchor, point) ? "caret" : "range";
    return { ...state, focus: point, mode };
}

renderSelectionHighlight.body:
export function renderSelectionHighlight(
    state: SelectionState,
    blockOrder: string[],
    wsaEl: HTMLElement | null,
): void {
    if (!wsaEl) return;

    // Nothing meaningful selected -> clear any existing paint and stop.
    if (state.anchor === null || state.focus === null || state.mode === "caret") {
        clearHighlight();
        return;
    }

    const range = buildResolvedRange(state.anchor, state.focus, blockOrder, wsaEl);
    if (range === null) {
        clearHighlight();
        return;
    }

    paintRange(range);
}

buildResolvedRange.body:
export function buildResolvedRange(
    anchor: SelectionPoint,
    focus: SelectionPoint,
    blockOrder: string[],
    _wsaEl: HTMLElement,
): Range | null {
    const start = earlierInDocument(anchor, focus, blockOrder);
    const end   = laterInDocument(anchor, focus, blockOrder);

    const startBoundary = boundaryFor(start);
    const endBoundary   = boundaryFor(end);
    if (!startBoundary || !endBoundary) return null;

    const range = document.createRange();
    range.setStart(startBoundary.node, startBoundary.offset);
    range.setEnd(endBoundary.node, endBoundary.offset);
    return range;
}

selection__range.body:
export function orderedSelectionRange(
    selection: SelectionState,
    order: string[],
): SelectionPoint[] {
    const { anchor, focus } = selection;
    if (!anchor) return [];
    if (!focus) return [wholeFromCaret(anchor)];

    const anchorIdx = order.indexOf(anchor.blockId);
    const focusIdx  = order.indexOf(focus.blockId);

    // Either end missing from the order list: fall back to the raw two points.
    if (anchorIdx === -1 || focusIdx === -1) return [anchor, focus];

    const start = documentStart(anchor, anchorIdx, focus, focusIdx);
    const end   = documentEnd(anchor, anchorIdx, focus, focusIdx);

    if (start.blockId === end.blockId) return [singleBlockSpan(start, end)];

    return spanAcrossBlocks(start, end, order);
}
